// shadcn
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger
} from "@/components/ui/accordion";

// constants
const faqs = [
  {
    question:
      "How Long Will It Take For My Order To Arrive After I Make Payment?",
    answer:
      "Because you are important to us, we want to know what you think about the products. As an added value, every time you rate the products you earn points which go straight to your account."
  },
  {
    question: "How Can I Change My Shipping Address?",
    answer:
      "You can change your shipping address by logging into your account and visiting the address book section in your profile settings."
  }
];

//  ------------------------------ | FAQ - 7 | ------------------------------  //

export default function Faq7() {
  return (
    <section className="bg-primary py-20 md:py-28">
      <div className="container mx-auto px-4">
        {/* Header */}
        <div className="mx-auto mb-16 max-w-sm text-center">
          <h2 className="mb-6 text-white">Got Questions ? We’ve Got Answers</h2>
          <p className="text-white">
            This is a big one and i consider it one of the most important things
            for a designer to get right.
          </p>
        </div>

        {/* FAQ List */}
        <div className="grid grid-cols-12">
          <div className="col-span-12 md:col-start-3 md:col-span-8 lg:col-start-4 lg:col-span-6">
            <Accordion className="space-y-4">
              {faqs.map((item, index) => (
                <AccordionItem
                  key={index}
                  value={`item-${index}`}
                  className="rounded-2xl bg-white px-6 py-2"
                >
                  <AccordionTrigger>
                    <span className="text-left font-semibold text-black text-lg">
                      {item.question}
                    </span>
                  </AccordionTrigger>
                  <AccordionContent className="text-muted-foreground text-md pb-6">
                    {item.answer}
                  </AccordionContent>
                </AccordionItem>
              ))}
            </Accordion>
          </div>
        </div>
      </div>
    </section>
  );
}
